class Solution:
    def friendRequests(self, n: int, restrictions: List[List[int]], requests: List[List[int]]) -> List[bool]:
        parent = list(range(n))
        rank = [1] * n

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            px, py = find(x), find(y)
            if px != py:
                if rank[px] > rank[py]:
                    parent[py] = px
                    rank[px] += rank[py]
                else:
                    parent[px] = py
                    rank[py] += rank[px]

        res = []
        for u, v in requests:
            pu, pv = find(u), find(v)
            valid = True
            for x, y in restrictions:
                px, py = find(x), find(y)
                if {pu, pv} == {px, py}:
                    valid = False
                    break
            res.append(valid)
            if valid:
                union(u, v)
        return res
